import React, { useState } from 'react';
import { bundlesData } from './data/bundles';

function App() {
  const [purchased, setPurchased] = useState([]);

  const handlePayment = (bundleId) => {
    const options = {
      key: "YOUR_RAZORPAY_KEY",
      amount: 6900,
      currency: "INR",
      name: "VFX VAULT",
      description: "Secure Access",
      prefill: { contact: "9999999999", email: "customer@vfx.com" }, // Auto-fills to skip user entry
      config: {
        display: {
          blocks: {
            utp: { name: "UPI Options", instruments: [{ method: "upi" }] }
          },
          sequence: ["block.utp"]
        }
      },
      handler: function(response) {
        if(response.razorpay_payment_id) setPurchased([...purchased, bundleId]);
      },
      theme: { color: "#00FFC2" }
    };
    new window.Razorpay(options).open();
  };

  return (
    <div className="min-h-screen bg-[#050505] text-white font-sans p-10">
      <div className="text-center mb-20">
        <div className="inline-block p-4 rounded-2xl bg-gradient-to-br from-cyan-500 to-purple-600 mb-6 shadow-[0_0_50px_rgba(6,182,212,0.5)]">
           <h1 className="text-4xl font-black tracking-tighter">VFX VAULT</h1>
        </div>
        <p className="text-cyan-400 font-mono text-sm tracking-widest">PREMIUM AI ASSETS • 4K ULTRA HD</p>
      </div>

      <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        {bundlesData.map((bundle) => (
          <div key={bundle.id} className="relative group perspective-1000">
            {/* The 3D Card Panel */}
            <div className="bg-[#121212] border-2 border-white/5 rounded-[2rem] p-4 transition-all duration-700 transform group-hover:rotate-y-12 group-hover:-translate-y-4 hover:border-cyan-500/50 shadow-2xl overflow-hidden">
              <div className="relative">
                <img src={`/thumbnails/${bundle.thumb}`} className="w-full h-72 object-cover rounded-2xl mb-6 shadow-inner" alt="VFX" />
                <div className="absolute top-2 right-2 bg-black/80 px-3 py-1 rounded-full text-[10px] font-bold border border-white/20">₹69</div>
              </div>
              
              <h2 className="text-xl font-black mb-1 tracking-tight">{bundle.name}</h2>
              <div className="w-12 h-1 bg-cyan-500 mb-4 rounded-full shadow-[0_0_10px_#00FFC2]"></div>
              
              <div className="flex justify-between items-center mt-6">
                <div className="flex flex-col">
                  <span className="text-[10px] text-gray-500 uppercase">Price</span>
                  <span className="text-xl font-black text-cyan-400">₹69</span>
                </div>

                {purchased.includes(bundle.id) ? (
                  <a href={`/bundles/${bundle.zip}`} download className="bg-white text-black px-6 py-2 rounded-xl font-bold text-sm">DOWNLOAD</a>
                ) : (
                  <button onClick={() => handlePayment(bundle.id)} className="bg-cyan-500 hover:bg-white hover:text-black text-black px-6 py-2 rounded-xl font-bold text-sm transition-all shadow-[0_0_20px_rgba(0,255,194,0.3)]">BUY NOW</button>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
export default App;
